create table if not exists public.owner_profiles (owner_id uuid primary key references auth.users(id), role text not null default 'owner' check (role in ('owner')), status text not null default 'active' check (status in ('active','disabled')), created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table if not exists public.sandbox_usage_monthly (owner_id uuid not null references auth.users(id), month_key text not null, estimated_cost_usd numeric not null default 0 check (estimated_cost_usd >= 0), actual_cost_usd numeric not null default 0 check (actual_cost_usd >= 0), request_count integer not null default 0 check (request_count >= 0), reserved_cost_usd numeric not null default 0 check (reserved_cost_usd >= 0), updated_at timestamptz not null default now(), primary key(owner_id, month_key));
create table if not exists public.sandbox_request_reservations (reservation_id uuid primary key default gen_random_uuid(), owner_id uuid not null references auth.users(id), idempotency_key text not null unique, estimated_cost_usd numeric not null check (estimated_cost_usd >= 0), status text not null default 'reserved' check (status in ('reserved','committed','released','expired')), expires_at timestamptz not null, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table if not exists public.sandbox_generation_cache (cache_key text primary key, owner_id uuid not null references auth.users(id), source_id text not null, source_version text not null, prompt_version text not null, result_payload jsonb not null, expires_at timestamptz, created_at timestamptz not null default now());
alter table public.owner_profiles enable row level security;
alter table public.sandbox_usage_monthly enable row level security;
alter table public.sandbox_request_reservations enable row level security;
alter table public.sandbox_generation_cache enable row level security;
create policy owner_profiles_self on public.owner_profiles for select using (owner_id = auth.uid());
create policy usage_self on public.sandbox_usage_monthly for select using (owner_id = auth.uid());
create policy cache_self on public.sandbox_generation_cache for select using (owner_id = auth.uid());
create or replace function public.reserve_sandbox_request(p_owner_id uuid, p_idempotency_key text, p_estimated_cost_usd numeric) returns jsonb language plpgsql security definer set search_path = '' as $$ declare v_month text := to_char(now(), 'YYYY-MM'); v_row public.sandbox_usage_monthly; v_res public.sandbox_request_reservations; begin if p_owner_id is null or p_estimated_cost_usd < 0 or p_estimated_cost_usd > 0.03 then raise exception 'authorization_or_request_limit'; end if; if not exists(select 1 from public.owner_profiles where owner_id=p_owner_id and role='owner' and status='active') then raise exception 'owner_not_active'; end if; insert into public.sandbox_usage_monthly(owner_id, month_key) values (p_owner_id, v_month) on conflict do nothing; select * into v_row from public.sandbox_usage_monthly where owner_id=p_owner_id and month_key=v_month for update; if v_row.estimated_cost_usd + v_row.reserved_cost_usd + p_estimated_cost_usd > 1.00 then raise exception 'monthly_limit'; end if; if exists(select 1 from public.sandbox_request_reservations where idempotency_key=p_idempotency_key and status in ('reserved','committed')) then raise exception 'duplicate_request'; end if; insert into public.sandbox_request_reservations(owner_id,idempotency_key,estimated_cost_usd,status,expires_at) values (p_owner_id,p_idempotency_key,p_estimated_cost_usd,'reserved',now()+interval '10 minutes') returning * into v_res; update public.sandbox_usage_monthly set reserved_cost_usd=reserved_cost_usd+p_estimated_cost_usd, updated_at=now() where owner_id=p_owner_id and month_key=v_month; return jsonb_build_object('reservationId',v_res.reservation_id); end $$;
create or replace function public.commit_sandbox_usage(p_owner_id uuid, p_reservation_id uuid, p_actual_cost_usd numeric) returns boolean language plpgsql security definer set search_path = '' as $$ declare v_res public.sandbox_request_reservations; begin if p_owner_id is null or p_actual_cost_usd < 0 then return false; end if; if not exists(select 1 from public.owner_profiles where owner_id=p_owner_id and role='owner' and status='active') then return false; end if; select * into v_res from public.sandbox_request_reservations where reservation_id=p_reservation_id for update; if v_res.owner_id <> p_owner_id or v_res.status <> 'reserved' or v_res.expires_at < now() then return false; end if; update public.sandbox_request_reservations set status='committed',updated_at=now() where reservation_id=p_reservation_id; update public.sandbox_usage_monthly set reserved_cost_usd=greatest(0,reserved_cost_usd-v_res.estimated_cost_usd),estimated_cost_usd=estimated_cost_usd+v_res.estimated_cost_usd,actual_cost_usd=actual_cost_usd+p_actual_cost_usd,request_count=request_count+1,updated_at=now() where owner_id=p_owner_id and month_key=to_char(now(),'YYYY-MM'); return true; end $$;
create or replace function public.release_sandbox_reservation(p_owner_id uuid, p_reservation_id uuid) returns boolean language plpgsql security definer set search_path = '' as $$ declare v_res public.sandbox_request_reservations; begin if p_owner_id is null then return false; end if; select * into v_res from public.sandbox_request_reservations where reservation_id=p_reservation_id for update; if v_res.owner_id <> p_owner_id or v_res.status <> 'reserved' then return false; end if; update public.sandbox_request_reservations set status='released',updated_at=now() where reservation_id=p_reservation_id; update public.sandbox_usage_monthly set reserved_cost_usd=greatest(0,reserved_cost_usd-v_res.estimated_cost_usd),updated_at=now() where owner_id=p_owner_id and month_key=to_char(now(),'YYYY-MM'); return true; end $$;
revoke all on function public.reserve_sandbox_request(uuid,text,numeric) from public;
revoke all on function public.reserve_sandbox_request(uuid,text,numeric) from anon;
revoke all on function public.reserve_sandbox_request(uuid,text,numeric) from authenticated;
grant execute on function public.reserve_sandbox_request(uuid,text,numeric) to service_role;
revoke all on function public.commit_sandbox_usage(uuid,uuid,numeric) from public;
revoke all on function public.commit_sandbox_usage(uuid,uuid,numeric) from anon;
revoke all on function public.commit_sandbox_usage(uuid,uuid,numeric) from authenticated;
grant execute on function public.commit_sandbox_usage(uuid,uuid,numeric) to service_role;
revoke all on function public.release_sandbox_reservation(uuid,uuid) from public;
revoke all on function public.release_sandbox_reservation(uuid,uuid) from anon;
revoke all on function public.release_sandbox_reservation(uuid,uuid) from authenticated;
grant execute on function public.release_sandbox_reservation(uuid,uuid) to service_role;
